import{_ as s,o as a,c as e,Q as n}from"./chunks/framework.699bb85b.js";const t="/Alan-blog/assets/nest-install.71fc1cda.jpg",l="/Alan-blog/assets/nest-start.6b229be1.jpg",p="/Alan-blog/assets/nest-project.643c0f6f.png",A=JSON.parse('{"title":"nestjs实践","description":"","frontmatter":{},"headers":[],"relativePath":"study/nestjs/practise.md","filePath":"study/nestjs/practise.md","lastUpdated":null}'),o={name:"study/nestjs/practise.md"},r=n(`<h1 id="nestjs实践" tabindex="-1">nestjs实践 <a class="header-anchor" href="#nestjs实践" aria-label="Permalink to &quot;nestjs实践&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>最近想学一下node做BFF层的一些东西，之前学过express框架配合MongoDB，做过一些简单的增删改查项目，有一点node基础，看到nestjs这几年特别火，决定学一下。网上搜了一些以前的别人的实践来试一下，这是我实践以后记录下来的一些实践经验和踩坑记录，做一个总结以及加深记忆。</p><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><p>Nest.js官网介绍：</p><blockquote><p>Nest (NestJS) 是一个用于构建高效、可扩展的 Node.js 服务器端应用程序的开发框架。它利用JavaScript 的渐进增强的能力，使用并完全支持 TypeScript （仍然允许开发者使用纯 JavaScript 进行开发），并结合了 OOP （面向对象编程）、FP （函数式编程）和 FRP （函数响应式编程）。 在底层，Nest 构建在强大的 HTTP 服务器框架上，例如 Express （默认），并且还可以通过配置从而使用 Fastify ！ Nest 在这些常见的 Node.js 框架 (Express/Fastify) 之上提高了一个抽象级别，但仍然向开发者直接暴露了底层框架的 API。这使得开发者可以自由地使用适用于底层平台的无数的第三方模块。</p></blockquote><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><p>先说一下nestjs的一些优点</p><ul><li>良好的ts支持</li><li>装饰器实现注解式的开发体验</li><li>方便集成Swagger、redis等</li><li>可以基于Express也可以选择fastify, 如果你对Express非常熟练， 直接用它的API也是没问题的</li></ul><h2 id="创建项目" tabindex="-1">创建项目 <a class="header-anchor" href="#创建项目" aria-label="Permalink to &quot;创建项目&quot;">​</a></h2><p>第一步先创建一个新项目</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki vitesse-dark vp-code-dark"><code><span class="line"><span style="color:#80A665;">npm</span><span style="color:#DBD7CAEE;"> </span><span style="color:#C98A7D;">i</span><span style="color:#DBD7CAEE;"> </span><span style="color:#C99076;">-g</span><span style="color:#DBD7CAEE;"> </span><span style="color:#C98A7D;">@nestjs/cli</span><span style="color:#DBD7CAEE;">  </span><span style="color:#C98A7D;">//</span><span style="color:#DBD7CAEE;"> </span><span style="color:#C98A7D;">全局安装Nest</span></span>
<span class="line"><span style="color:#80A665;">nest</span><span style="color:#DBD7CAEE;"> </span><span style="color:#C98A7D;">new</span><span style="color:#DBD7CAEE;"> </span><span style="color:#C98A7D;">project-name</span><span style="color:#DBD7CAEE;">  </span><span style="color:#C98A7D;">//</span><span style="color:#DBD7CAEE;"> </span><span style="color:#C98A7D;">创建项目</span></span></code></pre><pre class="shiki vitesse-light vp-code-light"><code><span class="line"><span style="color:#59873A;">npm</span><span style="color:#393A34;"> </span><span style="color:#B56959;">i</span><span style="color:#393A34;"> </span><span style="color:#A65E2B;">-g</span><span style="color:#393A34;"> </span><span style="color:#B56959;">@nestjs/cli</span><span style="color:#393A34;">  </span><span style="color:#B56959;">//</span><span style="color:#393A34;"> </span><span style="color:#B56959;">全局安装Nest</span></span>
<span class="line"><span style="color:#59873A;">nest</span><span style="color:#393A34;"> </span><span style="color:#B56959;">new</span><span style="color:#393A34;"> </span><span style="color:#B56959;">project-name</span><span style="color:#393A34;">  </span><span style="color:#B56959;">//</span><span style="color:#393A34;"> </span><span style="color:#B56959;">创建项目</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>推荐使用yarn和pnpm，记得更换淘宝镜像源，下载可以稍微顺畅一点，别再用那个taobao路径的源了，几年前就停止服务了。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki vitesse-dark vp-code-dark"><code><span class="line"><span style="color:#dbd7caee;">npm config set registry https://registry.npmmirror.com</span></span>
<span class="line"><span style="color:#dbd7caee;">yarn config set registry https://registry.npmmirror.com</span></span>
<span class="line"><span style="color:#dbd7caee;">pnpm config set registry https://registry.npmmirror.com</span></span></code></pre><pre class="shiki vitesse-light vp-code-light"><code><span class="line"><span style="color:#393a34;">npm config set registry https://registry.npmmirror.com</span></span>
<span class="line"><span style="color:#393a34;">yarn config set registry https://registry.npmmirror.com</span></span>
<span class="line"><span style="color:#393a34;">pnpm config set registry https://registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+t+'" alt="ssh"> nest需要比较高的node版本，18.17.0左右的版本，我常年用16.18.0左右的版本，所以还是下载了一个nvm去管理node版本升级一下。</p><p>这里有一个坑的点，是nvm安装后，发现nvm use不生效，这样一般两种情况：</p><ul><li>没开管理员权限</li><li>nvm和node路径冲突了</li></ul><p>网上很多答复都是重装node，我才不想又删一堆东西，万一还删不干净，重新安装又要卸载（重装噩梦），后来看到解决方法是把环境变量里的node环境变量删掉，完美解决。</p><p>第二个坑就是，切换node版本，如果那个版本没有安装nest，你会发现提示无法识别nest命令，你需要重新跑一遍install nest的命令。</p><h3 id="直接启动项目" tabindex="-1">直接启动项目 <a class="header-anchor" href="#直接启动项目" aria-label="Permalink to &quot;直接启动项目&quot;">​</a></h3><p><code>pnpm start</code>每次修改代码需要重新启动才能看到效果.</p><p>建议用 <code>pnpm start:dev</code>，因为这个是加了--watch监听的命令，更改代码能热更新。</p><p><img src="'+l+'" alt="ssh"></p><table><thead><tr><th>环境</th><th>版本</th></tr></thead><tbody><tr><td>Node.js</td><td>v18.17.0</td></tr><tr><td>npm</td><td>9.6.7</td></tr><tr><td>nestjs</td><td>10.3.2</td></tr></tbody></table><h2 id="文件结构" tabindex="-1">文件结构 <a class="header-anchor" href="#文件结构" aria-label="Permalink to &quot;文件结构&quot;">​</a></h2><p><img src="'+p+'" alt="alt text"></p><ul><li>dto: 我的理解就是这里主要是装入参类型的</li><li>entities：这里是定义接口返回值类型的</li><li>包含<code>spec</code>: 这个是写单元测试的</li><li>controller：后端的控制层，主要是定义接口路径、类型，还有一些拦截器使用等等</li><li>module： 我的理解就是这里是用于引入与导出，与其他模块交互，还有往这个模块底层注入一些其他模块的方法实体之类的，让全局可用</li><li>service： 主要业务逻辑的实现层，具体怎么查表联调操作之类的，都在这里写</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p><a href="https://juejin.cn/post/7032079740982788132" target="_blank" rel="noreferrer">https://juejin.cn/post/7032079740982788132</a></p>',29),c=[r];function i(d,h,y,m,u,b){return a(),e("div",null,c)}const _=s(o,[["render",i]]);export{A as __pageData,_ as default};
